  ('bali', 'Bali', 'Indonesia', 'Asia', 'Lush rice terraces, surf breaks, and temple-dotted hills. An island built for slow, soulful travel.', -8.4095, 115.1889, 70, 75, 80, 85, 60, 85, 4000, 1500, 1000),
